from flask import Flask, request
import xml.etree.ElementTree as ET

app = Flask(__name__)

MAX_XML_SIZE = 1_048_576  # 1 MB

@app.post("/upload")
def upload():
    '''
    Reads the XML from the incoming request.
    Parse it and return.
    '''
    if len(request.data) > MAX_XML_SIZE:
        return "Request too large", 413

    try:
        root = ET.fromstring(request.data.decode('utf-8'))
        return f"<root>{ET.tostring(root, encoding='unicode')}</root>", 200, {'Content-Type': 'application/xml'}
    except ET.ParseError:
        return "Invalid XML", 400
    except UnicodeDecodeError:
        return "Invalid encoding", 400
